var builder = DistributedApplication.CreateBuilder(args);

// WithDataVolume() attaches a named Docker volume so PostgreSQL data survives AppHost restarts.
// The volume name is auto-generated by Aspire (pattern: {app}-postgres-data).
// To list volumes: docker volume ls
// To reset local data intentionally: docker volume rm $(docker volume ls -q --filter name=postgres)
var db = builder.AddPostgres("postgres")
    .WithDataVolume()
    .AddDatabase("ChairlyDb");

var rabbitmq = builder.AddRabbitMQ("messaging")
    .WithDataVolume()
    .WithManagementPlugin();

builder.AddProject<Projects.Chairly_Api>("api")
    .WithReference(db)
    .WaitFor(db)
    .WithReference(rabbitmq)
    .WaitFor(rabbitmq)
    .WithUrlForEndpoint("http", ep => new ResourceUrlAnnotation { Url = "/scalar", DisplayText = "Scalar" });

builder.Build().Run();
